#include<bits/stdc++.h>
using namespace std;
const int MAXN=2e6+5;
deque<pair<int,int> > dq2;
int ans[MAXN],x,n,m,k;
int main(void){
    scanf("%d%d",&n,&k);pair<int,int> p;
    for(int i=0;i<n;++i){
        scanf("%d",&x),p.first=i,p.second=x;
		while(dq2.front().first<i-k)dq2.pop_front();
		ans[i]=((dq2.size())?(dq2.front().second):(0));
		while(dq2.size()&&dq2.back().second>=x)dq2.pop_back();dq2.push_back(p);
    }for(int i=0;i<n;++i)printf("%d\n",ans[i]);
    return false;
}
